// // This LFSR is designed to shift on every negative clock edge and has an asynchronous reset.
module lfsr (
    input clk,
    input reset,
    output reg [4:0] lfsr
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            lfsr <= 5'b00001;
        end else begin
            lfsr <= {lfsr[3:0], lfsr[4] ^ lfsr[2]};
        end
    end
endmodule
